mapper.select:
SELECT t.id, t.stock_code AS stockCode, s.company_name AS companyName, s.short_name AS shortName, t.instruction, t.execution_date AS executionDate, t.execution_time AS executionTime, t.execution_datetime AS executionDatetime, t.price, t.quantity, t.total_amount AS totalAmount, t.total_amount_display AS totalAmountDisplay, t.currency, t.is_settled AS isSettled, t.commission, t.tax, t.fee_total AS feeTotal, t.created_at AS createdAt, t.updated_at AS updatedAt FROM tb_stock_transaction_log t LEFT JOIN tb_stock_info s ON t.stock_code = s.stock_code WHERE t.user_id = #{userId}
AND t.instruction = #{query.tradeType}
AND (t.stock_code LIKE CONCAT('%', #{query.name}, '%') OR s.company_name LIKE CONCAT('%', #{query.name}, '%') OR s.short_name LIKE CONCAT('%', #{query.name}, '%'))
AND DATE(t.execution_datetime) >= #{query.tradeStartTime}
AND DATE(t.execution_datetime) <= #{query.tradeEndTime}
ORDER BY t.execution_datetime DESC, t.created_at DESC
